module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    reg [15:0] dividend_reg, divisor_reg;
    reg [3:0] cnt;
    reg [15:0] NEG_DIVISOR;
    reg [16:0] SR;
    reg [3:0] start_cnt;
    reg sign_reg;
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            res_valid <= 0;
        end
        else if (cnt[3]) begin
            res_valid <= 1;
        end
        else if (res_valid && res_ready) begin
            res_valid <= 0;
        end
        else begin
            res_valid <= res_valid;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            sign_reg <= 0;
        end
        else if (opn_valid && !res_valid) begin
            sign_reg <= sign;
        end
        else begin
            sign_reg <= sign_reg;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            dividend_reg <= 0;
        end
        else if (opn_valid && !res_valid) begin
            dividend_reg <= dividend;
        end
        else begin
            dividend_reg <= dividend_reg;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            divisor_reg <= 0;
        end
        else if (opn_valid && !res_valid) begin
            divisor_reg <= divisor;
        end
        else begin
            divisor_reg <= divisor_reg;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            cnt <= 0;
        end
        else if (res_valid) begin
            cnt <= 0;
        end
        else if (start_cnt) begin
            cnt <= cnt + 1;
        end
        else begin
            cnt <= cnt;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            start_cnt <= 0;
        end
        else if (res_valid) begin
            start_cnt <= 0;
        end
        else if (opn_valid && !res_valid) begin
            start_cnt <= 1;
        end
        else begin
            start_cnt <= start_cnt;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            NEG_DIVISOR <= 0;
        end
        else if (opn_valid && !res_valid) begin
            NEG_DIVISOR <= ~divisor_reg + 1;
        end
        else begin
            NEG_DIVISOR <= NEG_DIVISOR;
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            SR <= 0;
        end
        else if (opn_valid && !res_valid) begin
            SR <= {dividend_reg, 1'b0};
        end
        else if (start_cnt) begin
            if (cnt[3]) begin
                SR <= {SR[15:0], 1'b0};
            end
            else begin
                SR <= {SR[15:0], 1'b0};
                if (sub_res) begin
                    SR[0] <= 1'b1;
                end
                else begin
                    SR[0] <= 1'b0;
                end
            end
        end
        else begin
            SR <= SR;
        end
    end
    wire [15:0] sub_a;
    wire [15:0] sub_b;
    wire [15:0] sub_result;
    wire sub_cout;
    wire sub_res;
    assign sub_a = SR[15:0];
    assign sub_b = NEG_DIVISOR;
    assign {sub_cout, sub_result} = sub_a + sub_b;
    assign sub_res = !sub_cout;
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            result <= 0;
        end
        else if (cnt[3]) begin
            result <= {SR[15:0], 1'b0};
        end
        else begin
            result <= result;
        end
    end
endmodule
